import { ValidationError } from '../common/errors.js';
import type {
  RcsDeliveryReportPayload,
  RcsIncomingMessagePayload,
  RcsWebhookPayload,
} from '../common/types.js';

/**
 * Parse a raw webhook body (object or JSON string) into a typed RCS webhook payload.
 * Performs a minimal structural check — downstream code should rely on the
 * discriminated union (`direction`) via `isDeliveryReport` / `isIncomingMessage`.
 *
 * @throws {ValidationError} if the body is not a valid RCS webhook payload.
 */
export function parseWebhookPayload(body: unknown): RcsWebhookPayload {
  let parsed: unknown = body;

  if (typeof parsed === 'string') {
    try {
      parsed = JSON.parse(parsed);
    } catch {
      throw new ValidationError('Invalid webhook payload: not valid JSON');
    }
  }

  if (parsed === null || typeof parsed !== 'object') {
    throw new ValidationError('Invalid webhook payload: expected an object');
  }

  const record = parsed as Record<string, unknown>;

  if (record.type !== 'RCS') {
    throw new ValidationError('Invalid webhook payload: missing or unexpected `type` (expected "RCS")');
  }
  if (record.direction !== 'MT' && record.direction !== 'MO') {
    throw new ValidationError('Invalid webhook payload: `direction` must be "MT" or "MO"');
  }
  if (typeof record.messageId !== 'string') {
    throw new ValidationError('Invalid webhook payload: missing `messageId`');
  }

  return parsed as RcsWebhookPayload;
}

/** Type guard — true when the payload is a Delivery Report (MT). */
export function isDeliveryReport(
  payload: RcsWebhookPayload
): payload is RcsDeliveryReportPayload {
  return payload.direction === 'MT';
}

/** Type guard — true when the payload is an Incoming Message (MO). */
export function isIncomingMessage(
  payload: RcsWebhookPayload
): payload is RcsIncomingMessagePayload {
  return payload.direction === 'MO';
}
