import { BaseClient } from './base-client.js';
import { MessagesResource } from './resources/messages.js';
import { CampaignsResource } from './resources/campaigns.js';
import type {
  MessagePathOptions,
  PaginatedResponse,
  RcsBatchSendPayload,
  RcsListParams,
  RcsMessage,
  RcsSendPayload,
  RcsUpdatePayload,
  SmsmodeClientOptions,
} from './common/types.js';

/**
 * Main entry point of the `@smsmode/rcs`.
 *
 * Exposes RCS message methods directly on the instance, and namespaces the
 * Campaign resource under `.campaigns`.
 *
 * @example
 * ```ts
 * const client = new SmsmodeRcsClient({ apiKey: 'your-api-key' });
 * await client.send({ recipient: { to: '33612345678' }, body: { type: 'TEXT' } });
 * await client.campaigns.list();
 * ```
 */
export class SmsmodeRcsClient {
  private readonly messages: MessagesResource;
  public readonly campaigns: CampaignsResource;

  constructor(options: SmsmodeClientOptions) {
    const baseClient = new BaseClient(options);
    this.messages = new MessagesResource(baseClient);
    this.campaigns = new CampaignsResource(baseClient);
  }

  /** Send a single RCS message or a batch (max 1000) */
  send(payload: RcsSendPayload, options?: MessagePathOptions): Promise<RcsMessage>;
  send(payload: RcsBatchSendPayload, options?: MessagePathOptions): Promise<RcsMessage[]>;
  send(
    payload: RcsSendPayload | RcsBatchSendPayload,
    options?: MessagePathOptions
  ): Promise<RcsMessage | RcsMessage[]> {
    return this.messages.send(payload as RcsBatchSendPayload, options);
  }

  /** List messages with optional filters and pagination */
  list(
    params?: RcsListParams,
    options?: MessagePathOptions
  ): Promise<PaginatedResponse<RcsMessage>> {
    return this.messages.list(params, options);
  }

  /** Get a message by ID */
  get(messageId: string, options?: MessagePathOptions): Promise<RcsMessage> {
    return this.messages.get(messageId, options);
  }

  /** Update a scheduled message before it is sent */
  update(
    messageId: string,
    payload: RcsUpdatePayload,
    options?: MessagePathOptions
  ): Promise<RcsMessage> {
    return this.messages.update(messageId, payload, options);
  }

  /** Cancel a scheduled message before it is sent */
  cancel(messageId: string, options?: MessagePathOptions): Promise<void> {
    return this.messages.cancel(messageId, options);
  }
}
