import { BASE_URL, DEFAULT_HEADERS, API_KEY_HEADER } from './common/constants.js';
import { SmsModeApiError, SmsModeHttpError, AuthError, RateLimitError } from './common/errors.js';

function isStructuredApiError(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === 'object' &&
    value !== null &&
    'errorCode' in value &&
    typeof (value as Record<string, unknown>)['errorCode'] === 'string' &&
    'message' in value
  );
}
import type { SmsmodeClientOptions, RequestOptions } from './common/types.js';

export class BaseClient {
  private readonly apiKey: string;
  private readonly baseUrl: string;
  private readonly timeout: number;

  constructor(options: SmsmodeClientOptions) {
    if (!options.apiKey) {
      throw new Error('API key is required');
    }
    this.apiKey = options.apiKey;
    this.baseUrl = (options.baseUrl ?? BASE_URL).replace(/\/$/, '');
    this.timeout = options.timeout ?? 10000;
  }

  private encodeParams(params: Record<string, string | number | boolean | undefined>): string {
    const searchParams = new URLSearchParams();

    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined) {
        searchParams.append(key, String(value));
      }
    }

    return searchParams.toString();
  }

  private buildUrl(path: string, params?: Record<string, string | number | boolean | undefined>): string {
    const url = `${this.baseUrl}${path}`;
    if (params && Object.keys(params).length > 0) {
      return `${url}?${this.encodeParams(params)}`;
    }
    return url;
  }

  private async handleErrorResponse(response: Response): Promise<never> {
    let errorData: unknown;
    try {
      errorData = await response.json();
    } catch {
      errorData = undefined;
    }

    if (!isStructuredApiError(errorData)) {
      throw new SmsModeHttpError(response.status, response.statusText);
    }

    switch (response.status) {
      case 401:
        throw new AuthError(response.status, errorData);
      case 429: {
        const retryAfter = response.headers.get('Retry-After');
        throw new RateLimitError(response.status, errorData, retryAfter ? parseInt(retryAfter, 10) : undefined);
      }
      default:
        throw new SmsModeApiError(response.status, errorData);
    }
  }

  async request<T>(path: string, options: RequestOptions = {}): Promise<T> {
    const { method = 'GET', body, params } = options;
    const url = this.buildUrl(path, params);

    const headers: Record<string, string> = {
      ...DEFAULT_HEADERS,
      [API_KEY_HEADER]: this.apiKey,
    };

    if (method === 'GET' || method === 'DELETE') {
      delete headers['Content-Type'];
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => {
      controller.abort();
    }, this.timeout);

    try {
      const fetchOptions: RequestInit = {
        method,
        headers,
        signal: controller.signal,
      };
      if (body) {
        fetchOptions.body = JSON.stringify(body);
      }

      const response = await fetch(url, fetchOptions);

      if (!response.ok) {
        await this.handleErrorResponse(response);
      }

      if (response.status === 204) {
        return undefined as T;
      }

      return (await response.json()) as T;
    } finally {
      clearTimeout(timeoutId);
    }
  }

  async get<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T> {
    const options: RequestOptions = { method: 'GET' };
    if (params) options.params = params;
    return this.request<T>(path, options);
  }

  async post<T>(
    path: string,
    body?: unknown,
    params?: Record<string, string | number | boolean | undefined>
  ): Promise<T> {
    const options: RequestOptions = { method: 'POST' };
    if (body) options.body = body;
    if (params) options.params = params;
    return this.request<T>(path, options);
  }

  async patch<T>(
    path: string,
    body?: unknown,
    params?: Record<string, string | number | boolean | undefined>
  ): Promise<T> {
    const options: RequestOptions = { method: 'PATCH' };
    if (body) options.body = body;
    if (params) options.params = params;
    return this.request<T>(path, options);
  }

  async delete<T>(path: string, params?: Record<string, string | number | boolean | undefined>): Promise<T> {
    const options: RequestOptions = { method: 'DELETE' };
    if (params) options.params = params;
    return this.request<T>(path, options);
  }
}
