/** Base class for all SDK errors — enables a unified `instanceof RcsError` check. */
export class RcsError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'RcsError';
    Object.setPrototypeOf(this, new.target.prototype);
  }
}

/** Thrown when the response contains a structured smsmode error body. All fields are guaranteed. */
export class SmsModeApiError extends RcsError {
  readonly httpStatus: number;
  readonly title: string;
  readonly detail: string;
  readonly errorCode: string;
  readonly docsUrl: string;
  readonly details: unknown;

  constructor(httpStatus: number, body: Record<string, unknown>) {
    super(String(body['message']));
    this.name = 'SmsModeApiError';
    this.httpStatus = httpStatus;
    this.title = String(body['title']);
    this.detail = String(body['detail']);
    this.errorCode = String(body['errorCode']);
    this.docsUrl = typeof body['type'] === 'string' ? body['type'] : '';
    this.details = body;
  }

  override toString(): string {
    return `[${String(this.httpStatus)}] ${this.title} — ${this.message} (${this.detail}) [errorCode: ${this.errorCode}]`;
  }
}

/** Thrown when no structured smsmode body is present (5xx, proxy errors, empty bodies). */
export class SmsModeHttpError extends RcsError {
  constructor(
    public readonly httpStatus: number,
    public readonly statusText: string,
  ) {
    super(`HTTP ${String(httpStatus)}: ${statusText}`);
    this.name = 'SmsModeHttpError';
  }

  override toString(): string {
    return `HTTP ${String(this.httpStatus)}: ${this.statusText}`;
  }
}

/** Thrown on HTTP 401 — invalid or missing API key. */
export class AuthError extends SmsModeApiError {
  constructor(httpStatus: number, body: Record<string, unknown>) {
    super(httpStatus, body);
    this.name = 'AuthError';
  }
}

/** Thrown on HTTP 429 — rate limit exceeded. Check retryAfter for delay in seconds. */
export class RateLimitError extends SmsModeApiError {
  constructor(
    httpStatus: number,
    body: Record<string, unknown>,
    public readonly retryAfter?: number,
  ) {
    super(httpStatus, body);
    this.name = 'RateLimitError';
  }
}

/** Thrown when a webhook payload fails local structural validation (not an HTTP error). */
export class ValidationError extends RcsError {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}
