import type { BaseClient } from '../base-client.js';
import { RCS_API_PATH } from '../common/constants.js';
import { flattenGroup } from '../common/utils.js';
import type {
  CampaignPathOptions,
  PaginatedResponse,
  RcsCampaign,
  RcsCampaignListParams,
  RcsCampaignSendPayload,
  RcsCampaignUpdatePayload,
} from '../common/types.js';

/**
 * Campaigns resource — grouped RCS sends (max 1000 recipients per campaign)
 * and campaign statistics. Accessed via `client.campaigns` on {@link SmsmodeRcsClient}.
 */
export class CampaignsResource {
  constructor(private readonly client: BaseClient) {}

  private buildBasePath(options?: CampaignPathOptions): string {
    if (options?.channelId) return `${RCS_API_PATH}/channels/${options.channelId}`;
    return RCS_API_PATH;
  }

  private buildCampaignPath(campaignId: string, options?: CampaignPathOptions): string {
    return `${this.buildBasePath(options)}/campaigns/${campaignId}`;
  }

  private flattenListParams(
    params?: RcsCampaignListParams
  ): Record<string, string | number | boolean | undefined> {
    if (!params) return {};
    const { searchBy, sortBy, ...rest } = params;
    return {
      ...rest,
      ...flattenGroup('searchBy', searchBy),
      ...flattenGroup('sortBy', sortBy),
    };
  }

  /** Send or schedule a campaign (max 1000 recipients) */
  async send(
    payload: RcsCampaignSendPayload,
    options?: CampaignPathOptions
  ): Promise<RcsCampaign> {
    return this.client.post<RcsCampaign>(`${this.buildBasePath(options)}/campaigns`, payload);
  }

  /** List campaigns with optional filters and pagination */
  async list(
    params?: RcsCampaignListParams,
    options?: CampaignPathOptions
  ): Promise<PaginatedResponse<RcsCampaign>> {
    return this.client.get<PaginatedResponse<RcsCampaign>>(
      `${this.buildBasePath(options)}/campaigns`,
      this.flattenListParams(params)
    );
  }

  /** Get a campaign by ID */
  async get(campaignId: string, options?: CampaignPathOptions): Promise<RcsCampaign> {
    if (!campaignId) throw new Error('campaignId is required');
    return this.client.get<RcsCampaign>(this.buildCampaignPath(campaignId, options));
  }

  /** Update a scheduled campaign before it is sent */
  async update(
    campaignId: string,
    payload: RcsCampaignUpdatePayload,
    options?: CampaignPathOptions
  ): Promise<RcsCampaign> {
    if (!campaignId) throw new Error('campaignId is required');
    return this.client.patch<RcsCampaign>(
      this.buildCampaignPath(campaignId, options),
      payload
    );
  }

  /** Cancel a scheduled campaign before it is sent */
  async cancel(campaignId: string, options?: CampaignPathOptions): Promise<void> {
    if (!campaignId) throw new Error('campaignId is required');
    await this.client.delete(this.buildCampaignPath(campaignId, options));
  }
}
