import type { BaseClient } from '../base-client.js';
import { RCS_API_PATH } from '../common/constants.js';
import { flattenGroup } from '../common/utils.js';
import type {
  MessagePathOptions,
  PaginatedResponse,
  RcsBatchSendPayload,
  RcsListParams,
  RcsMessage,
  RcsSendPayload,
  RcsUpdatePayload,
} from '../common/types.js';

/**
 * Messages resource — RCS unit and batch sends, listing, retrieval,
 * update of scheduled messages and cancellation.
 *
 * Typically accessed as flat methods on {@link SmsmodeRcsClient} rather than
 * instantiated directly.
 */
export class MessagesResource {
  constructor(private readonly client: BaseClient) {}

  private buildBasePath(options?: MessagePathOptions): string {
    const base = RCS_API_PATH;
    if (options?.channelId && options.campaignId) {
      return `${base}/channels/${options.channelId}/campaigns/${options.campaignId}`;
    }
    if (options?.channelId) return `${base}/channels/${options.channelId}`;
    if (options?.campaignId) return `${base}/campaigns/${options.campaignId}`;
    return base;
  }

  private buildMessagePath(messageId: string, options?: MessagePathOptions): string {
    return `${this.buildBasePath(options)}/messages/${messageId}`;
  }

  private flattenListParams(
    params?: RcsListParams
  ): Record<string, string | number | boolean | undefined> {
    if (!params) return {};
    const { searchBy, sortBy, ...rest } = params;
    return {
      ...rest,
      ...flattenGroup('searchBy', searchBy),
      ...flattenGroup('sortBy', sortBy),
    };
  }

  /** Send a single RCS message or a batch (max 1000) */
  async send(payload: RcsSendPayload, options?: MessagePathOptions): Promise<RcsMessage>;
  async send(payload: RcsBatchSendPayload, options?: MessagePathOptions): Promise<RcsMessage[]>;
  async send(
    payload: RcsSendPayload | RcsBatchSendPayload,
    options?: MessagePathOptions
  ): Promise<RcsMessage | RcsMessage[]> {
    const response = await this.client.post<RcsMessage | Array<{ message: RcsMessage }>>(
      `${this.buildBasePath(options)}/messages`,
      payload
    );
    if (Array.isArray(response)) {
      return response.map((item) => item.message);
    }
    return response;
  }

  /** List messages with optional filters and pagination */
  async list(
    params?: RcsListParams,
    options?: MessagePathOptions
  ): Promise<PaginatedResponse<RcsMessage>> {
    return this.client.get<PaginatedResponse<RcsMessage>>(
      `${this.buildBasePath(options)}/messages`,
      this.flattenListParams(params)
    );
  }

  /** Get a message by ID */
  async get(messageId: string, options?: MessagePathOptions): Promise<RcsMessage> {
    if (!messageId) throw new Error('messageId is required');
    return this.client.get<RcsMessage>(this.buildMessagePath(messageId, options));
  }

  /** Update a scheduled message before it is sent */
  async update(
    messageId: string,
    payload: RcsUpdatePayload,
    options?: MessagePathOptions
  ): Promise<RcsMessage> {
    if (!messageId) throw new Error('messageId is required');
    return this.client.patch<RcsMessage>(this.buildMessagePath(messageId, options), payload);
  }

  /** Cancel a scheduled message before it is sent */
  async cancel(messageId: string, options?: MessagePathOptions): Promise<void> {
    if (!messageId) throw new Error('messageId is required');
    await this.client.delete(this.buildMessagePath(messageId, options));
  }
}
